// OpenCL kernel implementation for LU Decomposition
// Translated from OpenMP source

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i, j, k;
    int idx = get_global_id(0);

    // Only one thread executes the sequential diagonal block update
    // The outer loop over 'i' is sequential due to dependencies
    if (idx == 0) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            // Update upper part of the diagonal block (row i, cols j=i..BS-1)
            // This computes U[i, j]
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
                }
                a[(offset + i) * size + (offset + j)] -= sum;
            }

            // Compute 1/U[i,i] for scaling the column
            float temp_val = 1.0f / a[(offset + i) * size + (offset + i)];

            // Update lower part of the diagonal block (col i, rows j=i+1..BS-1)
            // This computes L[j, i]
            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
                }
                a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * temp_val;
            }
        }
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag, const int size, const int offset)
{
    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    int global_id = get_global_id(0);
    int local_id = get_local_id(0);
    int block_id = global_id / (2 * BLOCK_SIZE);
    int thread_in_block = global_id % (2 * BLOCK_SIZE);

    if (block_id >= chunks_in_inter_row) return;

    int i, j, k;
    float sum;

    // Note: We access the diagonal block directly from global memory to avoid complex local memory loading
    // logic that might cause errors with the given thread block size (2*BLOCK_SIZE) vs block size (BLOCK_SIZE*BLOCK_SIZE).
    // The local buffers (temp_top, temp_left, temp_diag) are allocated by the host but we rely on global access for correctness.

    if (thread_in_block < BLOCK_SIZE) {
        // Right perimeter: Update row (offset + thread_in_block), cols (offset + BS + block_id*BS ...)
        // This updates the U part for the blocks to the right of the diagonal block
        int i_local = thread_in_block;
        int j_block_start = offset + BLOCK_SIZE * (block_id + 1);

        for (int j_local = 0; j_local < BLOCK_SIZE; j_local++) {
            sum = 0.0f;
            int j_global = j_block_start + j_local;
            int i_global = offset + i_local;

            for (int k = 0; k < i_local; k++) {
                // A[offset+i, offset+k] is L[i, k] (from diagonal block)
                // A[offset+k, j_global] is U[k, j] (from right block, being updated)
                sum += a[(offset + i_local) * size + (offset + k)] * a[(offset + k) * size + j_global];
            }

            a[i_global * size + j_global] -= sum;
        }
    } else {
        // Left perimeter: Update col (offset + thread_in_block - BLOCK_SIZE), rows > offset+BS
        // This updates the L part for the blocks below the diagonal block
        int j_local = thread_in_block - BLOCK_SIZE;
        int i_block_start = offset + BLOCK_SIZE * (block_id + 1);

        for (int i_local = 0; i_local < BLOCK_SIZE; i_local++) {
            sum = 0.0f;
            int i_global = i_block_start + i_local;
            int j_global = offset + j_local;

            for (int k = 0; k < j_local; k++) {
                // A[i_global, offset+k] is L[i, k] (from left block, being updated)
                // A[offset+k, offset+j_local] is U[k, j] (from diagonal block)
                sum += a[i_global * size + (offset + k)] * a[(offset + k) * size + (offset + j_local)];
            }

            // Divide by diagonal element U[j, j]
            float diag_val = a[(offset + j_local) * size + (offset + j_local)];
            a[i_global * size + j_global] = (a[i_global * size + j_global] - sum) / diag_val;
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int blocks_per_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    int block_x = get_global_id(0) / BLOCK_SIZE;
    int block_y = get_global_id(1) / BLOCK_SIZE;

    if (block_x >= blocks_per_row || block_y >= blocks_per_row) return;

    int i_global_base = offset + BLOCK_SIZE * (1 + block_y);
    int j_global_base = offset + BLOCK_SIZE * (1 + block_x);

    int i_local = get_global_id(0) % BLOCK_SIZE;
    int j_local = get_global_id(1) % BLOCK_SIZE;

    // Load temp_top: from diagonal block rows, current block columns
    // Represents U[k, j] where k is in diagonal block, j in current block
    temp_top[i_local * BLOCK_SIZE + j_local] = a[(offset + i_local) * size + (j_global_base + j_local)];

    // Load temp_left: from current block rows, diagonal block columns
    // Represents L[i, k] where i is in current block, k in diagonal block
    temp_left[i_local * BLOCK_SIZE + j_local] = a[(i_global_base + i_local) * size + (offset + j_local)];

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute sum: L[i, k] * U[k, j]
    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[i_local * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j_local];
    }

    int i_here = i_global_base + i_local;
    int j_here = j_global_base + j_local;

    a[i_here * size + j_here] -= sum;
}
